SELECT ch.id AS h_id, ch.coupon_id, ch.member_id, ch.coupon_code, ch.member_nickname, ch.get_type, ch.create_time, ch.use_status, ch.use_time, ch.order_id, ch.order_sn, c.id AS c_id, c.type AS c_type, c.name AS c_name, c.platform AS c_platform, c.count AS c_count, c.amount AS c_amount, c.per_limit AS c_per_limit, c.min_point AS c_min_point, c.start_time AS c_start_time, c.end_time AS c_end_time, c.use_type AS c_use_type, c.note AS c_note, c.publish_count AS c_publish_count, c.use_count AS c_use_count, c.receive_count AS c_receive_count, c.enable_time AS c_enable_time, c.code AS c_code, c.member_level AS c_member_level, c.status AS c_status FROM sms_coupon_history ch LEFT JOIN sms_coupon c ON ch.coupon_id = c.id WHERE ch.member_id = #{memberId}
AND ch.use_status = #{useStatus} AND NOW() > c.start_time AND c.end_time > NOW()
AND NOW() > c.end_time
